text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        {
          "item": "릴리스 공개 시점은 smoke 테스트 통과 시 금요일 15:00 KST로 확정."
        },
        {
          "item": "packageName 불일치가 발생해도 smoke-theme-pack.mjs에서 일괄 무시 처리하지 않음. 먼저 패키지 설정(계약/구성)을 점검하고, 계약 자체가 잘못된 경우에만 스크립트 재검토."
        }
      ],
      "rejected_proposals": [
        {
          "proposal": "smoke-theme-pack.mjs를 수정해 packageName 불일치를 무시하도록 변경",
          "result": "회의에서 거부됨"
        }
      ]
    },
    "non_decisions": [
      {
        "item": "README 설치 단계 검토는 목요일 가능 시 수행하자는 제안만 있었고, 최종 담당자·마감 확정은 없음."
      },
      {
        "item": "Minjun smoke 결과 공유 후 Hara가 생성 tarball 경로를 확인한다는 항목은 확인되었으나, 정확한 마감 시간은 미확정."
      }
    ],
    "stretch_goals": [
      {
        "item": "수요일 배포는 내부 stretch goal로만 언급되었고, 공식 공개 릴리스 결정으로 확정되지 않음."
      }
    ],
    "risks": [
      {
        "item": "tarball 경로가 잘못되면 릴리스 일정이 지연될 수 있음."
      },
      {
        "item": "README 설치 단계가 구식이면 릴리스 노트가 사용자에게 오해를 줄 수 있음."
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "item": "릴리스 노트에 수요일 내부 stretch goal 언급을 포함할지 미결정."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke 테스트를 재실행하고 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Seoyeon",
      "task": "README 설치 단계 검토를 목요일 내로 가능하면 수행",
      "due": "목요일(가능 시)",
      "status": "미결(담당자 확정 아님)",
      "source_certainty": "중간"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 공유한 뒤 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "미결(의존성 존재)",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 금요일 10:00 KST smoke 재실행 결과가 확인되었는지 점검",
      "Doyun의 금요일 12:00 KST 실패 트리아지 노트 작성 완료 여부 점검",
      "Hara가 smoke 결과 공유 후 tarball 경로를 확인했는지 추적",
      "최종 릴리스 승인 권한자와 수요일 stretch goal 노출 여부를 별도 확정",
      "README 설치 단계 검토 담당자와 실제 반영 여부 재확인"
    ],
    "what_not_to_invent": [
      "고객명/외부 파트너명",
      "예산 수치",
      "보안 사고 또는 장애 관련 사실",
      "법무 승인 요구사항",
      "기존에 언급되지 않은 오너 또는 최종 마감일"
    ]
  },
  "non_invention_rules": [
    "회의록에 없는 고객·예산·보안·장애·법무 승인 사실은 생성하지 않는다.",
    "확인되지 않은 오너 정보는 임의로 부여하지 않고 미정/미확정으로 표시한다.",
    "제시되지 않은 마감일은 임의 추정하지 않고 미확정으로 남긴다.",
    "열린 질문은 질문 형태로 유지하고 결론으로 해석해 단정하지 않는다.",
    "회귀/가설 기반 내용(예: 내부 승인 절차 상세, 추가 책임 범위)은 fixture에 없는 한 제외한다."
  ]
}
